Javascript.validate:
var description = Services.getValue(REF_DATA_XPATH + "/TransferReasonList/TransferReason[./Value = " + TransferReason.dataBinding + "]/Description");
var valueTest = Services.getValue( REF_DATA_XPATH + "/TransferReasonList/TransferReason[./Description = " + TransferReason.dataBinding + "]/Value" );
if (description == null && valueTest == null)
{
	// This is not a valid value - see list of Values
	return ErrorCode.getErrorCode("CaseMan_Reports_Invalid_LOV_Msg");
}
else
{
	return null;
}

Javascript.transformToDisplay:
var description = Services.getValue( REF_DATA_XPATH + "/TransferReasonList/TransferReason[./Value = " + TransferReason.dataBinding + "]/Description" );
if (description != null)
{
	return description;
}
else
{
	return value;
}

Javascript.miscCode:
  TransferReason.initialise = function() 
  { 
		dom = getList("../LOV/TransferReasonList.xml"); 
		Services.addNode(dom, REF_DATA_XPATH);
		return false; 
  }
  
  	TransferReason.srcData 		  = REF_DATA_XPATH + "/TransferReasonList";
	TransferReason.rowXPath 	  = "TransferReason";
	TransferReason.keyXPath 	  = "Value";
	
	function TransferReasonLOVButton() {}
	TransferReasonLOVButton.tabIndex = __tabIdx++;
	
	function TransferReasonLOVGrid() {};
	TransferReasonLOVGrid.dataBinding = TransferReason.dataBinding;
	TransferReasonLOVGrid.srcData 	  = REF_DATA_XPATH + "/TransferReasonList";
	TransferReasonLOVGrid.rowXPath    = "TransferReason";
	TransferReasonLOVGrid.keyXPath    = "Value";
	TransferReasonLOVGrid.columns     = [
		{xpath: "Value"},
		{xpath: "Description"}
	];
	TransferReasonLOVGrid.raise = {
		eventBinding: {
			singleClicks: [ {element: "TransferReasonLOVButton"} ],
			keys: [ { key: Key.F6, element: "TransferReason" } ]
		}
	};
